{"command": "# Use addr2line with -a and also try using the .symtab
# Let's search nearby for proper function names
for addr in 0x2f4b20 0x2f4c84; do
  echo "=== $addr ==="
  # Look at the symbol table for the nearest function
  readelf -sW /tmp/mono_debug2 | awk -v target="$addr" '
    BEGIN { target_dec = strtonum(target) }
    /FUNC/ && $2 ~ /^[0-9a-f]+$/ { 
      addr = strtonum("0x"$2)
      size = strtonum("0x"$3)
      if (addr <= target_dec && addr + size > target_dec) print $0
    }' | head -3
done", "description": "Find enclosing function symbols"}

arguments.command:
# Try with nm to find nearest symbols
nm --defined-only -n /tmp/mono_debug2 | awk '
/^[0-9a-f]+ [tTwW]/ {
  addr = strtonum("0x"$1)
  if (addr <= 0x2f4b20) { prev1 = $0; prevaddr1 = addr }
  if (addr <= 0x2f4c84) { prev2 = $0; prevaddr2 = addr }
}
