arguments.command:
# Find the exact thunk names for both addresses
nm --defined-only -n /tmp/mono_debug2 | awk '
{
  if (NF >= 3) {
    addr = strtonum("0x"$1)
    name = $3
    if (addr <= 0x2f4b20) { prev_name_1 = name; prevaddr_1 = addr }
    if (addr <= 0x2f4c84) { prev_name_2 = name; prevaddr_2 = addr }
  }
}
END {
  printf "0x2f4b20 → %s (base 0x%x)\n", prev_name_1, prevaddr_1
  printf "0x2f4c84 → %s (base 0x%x)\n", prev_name_2, prevaddr_2
}' 

# Now let's find the actual thunk target addresses
# Also look for the thunk closest below 0x2f4c84
nm --defined-only -n /tmp/mono_debug2 | grep CortexA53 | awk '{
  addr = strtonum("0x"$1)
  if (addr <= 0x2f4c84) printf "%s %s %s\n", $1, $2, $3
}' | tail -5

